from source import filter_expensive_items

def test_type_coercion_price():
    items = [{'name': 'A', 'price': 100}, {'name': 'B', 'price': '200'}, {'name': 'C', 'price': 50}]
    threshold = 150
    try:
        result = filter_expensive_items(items, threshold)
        assert len(result) == 1 and result[0]['name'] == 'B', "Expected filter_expensive_items to return only items with price above threshold"
    except TypeError as e:
        assert False, f"Expected filter_expensive_items to handle mixed price types, but got TypeError: {e}"
